export const API_BROWSER = "- `browser.getPage(nameOrId)` ‚Äî get-or-create a named page, or attach to an existing tab by the\n  `id` from `listPages()`. Named pages persist across steps in a session ‚Äî call with the same\n  name to reuse the tab.\n- `browser.newPage()` ‚Äî an anonymous page, auto-closed when the script ends; does not persist.\n- `browser.listPages()` ‚Äî list every open tab: `[{ id, url, title, name }]` (`name` is `null`\n  for tabs you never named).\n- `browser.closePage(name)` ‚Äî close and forget a named page.";

export const API_CONSOLE = "- `console.log` / `console.info` write to stdout; `console.warn` / `console.error` write to\n  stderr. Top-level `console.log` is your script's output channel.\n- `console.log` inside `page.evaluate(() => ‚Ä¶)` runs in the page and is captured into the\n  session's console artifact instead.";

export const API_FILE_HELPERS = "All file I/O is async (await it), sandboxed to `~/.canary/tmp/` (no filesystem escape), and\nreturns the full path to the file:\n\n- `saveScreenshot(buffer, name)` ‚Äî persist a screenshot buffer; buffer first:\n  `const path = await saveScreenshot(await page.screenshot(), \"home.png\");`\n- `writeFile(name, data)` ‚Äî write a small file (e.g. JSON state):\n  `await writeFile(\"results.json\", JSON.stringify(data));`\n- `readFile(name)` ‚Äî read it back (returns the contents as a string):\n  `const data = JSON.parse(await readFile(\"results.json\"));`";

export const API_GLOBALS = "Every script gets these globals:\n\n- `browser` ‚Äî pre-connected browser handle (see the script API)\n- `console` ‚Äî `log` / `info` / `warn` / `error`, captured per run\n- `setTimeout` / `clearTimeout` ‚Äî basic timers\n- `saveScreenshot(buffer, name)` ‚Äî save a screenshot buffer (async ‚Äî await it)\n- `writeFile(name, data)` / `readFile(name)` ‚Äî small-file persistence (async ‚Äî await them)";

export const API_PLAYWRIGHT_METHODS = "- `page.goto(url, { waitUntil: \"domcontentloaded\" })` ‚Äî navigate; `waitUntil` is `\"load\"` /\n  `\"domcontentloaded\"` / `\"networkidle\"` (prefer `\"domcontentloaded\"` on dev servers)\n- `page.title()` / `page.url()` ‚Äî current title / URL\n- `page.snapshotForAI(options)` ‚Äî AI-optimized page outline; returns `{ full, incremental? }`;\n  options `{ track?, depth?, timeout? }`\n- `page.getByRole(role, { name })` / `page.getByText(text)` ‚Äî semantic locators (survive re-renders)\n- `page.textContent(sel)` / `page.innerText(sel)` / `page.innerHTML(sel)` /\n  `page.getAttribute(sel, name)` ‚Äî read by selector\n- `page.inputValue(sel)` / `page.isChecked(sel)` / `page.isVisible(sel)` / `page.isHidden(sel)` ‚Äî\n  input and visibility state\n- `page.fill(sel, value)` / `page.click(sel)` / `page.type(sel, text)` / `page.press(sel, key)` ‚Äî\n  act on elements\n- `page.waitForSelector(sel, { state, timeout })` (`state`: `\"attached\"` / `\"visible\"` /\n  `\"hidden\"` / `\"detached\"`) / `page.waitForURL(pattern)` / `page.waitForLoadState(state)` /\n  `page.waitForFunction(fn)` / `page.waitForTimeout(ms)` ‚Äî waiting\n- `page.screenshot({ fullPage })` ‚Äî capture a screenshot Buffer; save it with `saveScreenshot(...)`\n- `page.evaluate(fn[, arg])` / `page.$eval(sel, fn)` / `page.$$eval(sel, fn)` ‚Äî run plain\n  JavaScript in the page context (real DOM; args/returns must be serializable)\n- `page.locator(sel)` ‚Äî a Locator for chained actions (`.click()`, `.fill(value)`,\n  `.textContent()`, `.first()`, ‚Ä¶)\n- `page.keyboard.press/type/down/up(...)` / `page.mouse.move/click/down/up(...)` ‚Äî low-level input\n- `page.reload()` / `page.goBack()` / `page.goForward()` ‚Äî history;\n  `page.content()` / `page.setContent(html)` ‚Äî full HTML\n- `page.on(\"console\", handler)` ‚Äî observe page console events";

export const API_PLAYWRIGHT_NOTE = "Pages returned by `browser.getPage()` and `browser.newPage()` are full Playwright Page objects ‚Äî\nthe same API (`goto`, `click`, `fill`, `locator`, `evaluate`, `getByRole`, `waitForSelector`, ‚Ä¶):\nhttps://playwright.dev/docs/api/class-page";

export const API_SANDBOX_ENV = "Scripts execute inside a QuickJS WASM sandbox with no arbitrary access to the host system.\nThis is NOT Node.js ‚Äî there is no module system and no Node API:\n\n- `require()` / `import()` ‚Äî no module loading; inline any helpers in the script\n- `process`, `fs` / `path` / `os` ‚Äî no process or direct filesystem access (use the file helpers)\n- `fetch` / `WebSocket` ‚Äî no direct network access (the page does the networking)\n- `__dirname` / `__filename` ‚Äî no path globals\n\nMemory and CPU limits are enforced, and both CPU time and wall-clock time are bounded ‚Äî infinite\nloops or never-settling promises abort the script. Values crossing `evaluate` / `$eval` must be\nJSON-serializable.";

export const API_SNAPSHOT = "- `page.snapshotForAI()` returns `{ full, incremental? }` ‚Äî `full` is an aria outline of the\n  page: roles, accessible names, `[ref=eN]` markers on actionable nodes. Read it to pick a\n  semantic selector ‚Äî `page.getByRole(\"button\", { name: \"Continue\" })`,\n  `page.getByText(\"Sign in\")` ‚Äî then act.\n- Options `{ track?, depth?, timeout? }`: re-run `page.snapshotForAI({ track: \"main\" })` after\n  the page changes to get just the `incremental` diff; `{ depth: N }` caps the tree on huge\n  pages; `timeout` bounds the walk.\n- `page.locator(\"aria-ref=e12\")` works for an immediate action in the same script only ‚Äî refs go\n  stale across steps and after navigations. Prefer re-deriving a semantic selector.";

export const EX_INSPECT_TABS = "const tabs = await browser.listPages();\nconsole.log(JSON.stringify(tabs, null, 2));";

export const EX_QUICKSTART = "const page = await browser.getPage(\"main\");          // named, persistent page\nawait page.goto(\"https://example.com\", { waitUntil: \"domcontentloaded\" });\nconsole.log(await page.title());\n\nconst headings = await page.evaluate(() =>\n  [...document.querySelectorAll(\"h1, h2\")].map((h) => h.textContent.trim())\n);\nconsole.log(JSON.stringify(headings));\n\nawait page.locator(\"a.more\").click();\nconst buf = await page.screenshot({ fullPage: false });\nawait saveScreenshot(buf, \"page.png\");               // saveScreenshot(buffer, name)";

