export const RULE_DATA_PASSING = "- Browser state persists across steps: named pages (and their cookies) stay open between scripts\n  within a session ‚Äî reuse the same page name so each step picks up where the last left off.\n- Anonymous `newPage()` tabs are closed when each script ends.\n- To pass values between steps: `writeFile(\"state.json\", JSON.stringify(x))` in one step,\n  `JSON.parse(await readFile(\"state.json\"))` in the next.";

export const RULE_DEV_SERVER = "For local dev servers (Next.js, Vite, ‚Ä¶) prefer\n`await page.goto(url, { waitUntil: \"domcontentloaded\" })` ‚Äî the default `\"load\"` wait can hang\non HMR, streaming, or other long-lived dev-server connections. Use `\"load\"` only when you\nspecifically need every subresource to finish loading.";

export const RULE_FAIL_FAST = "- End each script by logging the state you need for the next decision ‚Äî stdout is your\n  observation channel.\n- Use short timeouts (`canary run --timeout 10`) so a step fails fast instead of hanging on a\n  missing element.\n- In assertion / extraction steps, degrade gracefully ‚Äî log a `WARN` / `FAIL` line instead of\n  crashing, so the step still records its evidence. While exploring, a missed selector means\n  look again (snapshot, fix, retry as a new step), not a silent fallback.\n- End before you stop: `canary stop` shuts the daemon down and aborts any live session,\n  skipping its report.html ‚Äî always `canary session end <id>` first.";

export const RULE_OBSERVE_FIRST = "- Unknown page? Snapshot first, then act: read `(await page.snapshotForAI()).full` to see what\n  is there, pick a semantic selector from it (`getByRole`, `getByText`), then interact. Never\n  guess selectors blind.\n- Known page or selectors? Skip the snapshot and use direct selectors ‚Äî faster and more reliable.";

export const RULE_SCREENSHOT = "After each `canary run --step`, the daemon auto-captures ONE screenshot of the step's\nlast-opened tab and binds it to that step in the report. So:\n\n- Keep one primary named page per step ‚Äî the report screenshot is always the page you mean.\n- If a step opens several tabs, open the one you want featured last.\n- `saveScreenshot(...)` images land in `~/.canary/tmp/` and are NOT in the report ‚Äî they're\n  extras for debugging.";
